// Topic: sensors/{project}/{position}/{device_id}/{sensor_type}
const parts = (msg.topic || "").split("/");
if (parts.length !== 5 || parts[0] !== "sensors") {
    node.warn(`Skipping non-sensor topic: ${msg.topic}`);
    return null;
}
const [, project, position, device_id, sensor_type] = parts;

const d = msg.payload || {};

// Build fields: every finite number in the payload, except 'fw' (which is a tag).
const fields = {};
for (const [k, v] of Object.entries(d)) {
    if (k === "fw") continue;
    if (typeof v === "number" && Number.isFinite(v)) fields[k] = v;
}

if (Object.keys(fields).length === 0) {
    node.warn(`No numeric fields in payload from ${msg.topic}: ${JSON.stringify(d)}`);
    return null;
}

const tags = { project, position, device_id };
if (typeof d.fw === "string" && d.fw.length > 0) tags.fw = d.fw;

// node-red-contrib-influxdb v0.7.x in v2 mode reads measurement from msg.measurement
// when the node's own `measurement` config is left blank; payload carries fields+tags.
msg.measurement = sensor_type;
msg.payload = [fields, tags];
return msg;
